1	type Cell = [number, number]; // [x, y]
2	
3	const NEIGHBOR_OFFSETS: Cell[] = [
4	  [-1, -1], [0, -1], [1, -1],
5	  [-1, 0], [1, 0],
6	  [-1, 1], [0, 1], [1, 1],
7	];
8	const BIRTH_NEIGHBORS = 3;
9	const SURVIVAL_NEIGHBORS = 2;
10	
11	function key(x: number, y: number): string {
12	  return `${x},${y}`;
13	}
14	
15	function countLiveNeighbors(cells: Cell[]): Map<string, number> {
16	  const counts = new Map<string, number>();
17	  for (const [x, y] of cells) {
18	    for (const [dx, dy] of NEIGHBOR_OFFSETS) {
19	      const neighbor = key(x + dx, y + dy);
20	      counts.set(neighbor, (counts.get(neighbor) ?? 0) + 1);
21	    }
22	  }
23	  return counts;
24	}
25	
26	export function nextGeneration(cells: Cell[]): Cell[] {
27	  const living = new Set(cells.map(([x, y]) => key(x, y)));
28	  const neighborCounts = countLiveNeighbors(cells);
29	
30	  const next: Cell[] = [];
31	  for (const [cellKey, count] of neighborCounts) {
32	    const survives = count === SURVIVAL_NEIGHBORS && living.has(cellKey);
33	    const born = count === BIRTH_NEIGHBORS;
34	    if (survives || born) {
35	      const [x, y] = cellKey.split(",").map(Number);
36	      next.push([x, y]);
37	    }
38	  }
39	  return next;
40	}
