6	    expect(nextGeneration([])).toEqual([]);
7	  });
8	  it("a single living cell dies from underpopulation — [(0,0)] → []", () => {
9	    expect(nextGeneration([[0, 0]])).toEqual([]);
10	  });
11	  it("a pair of living cells both die from underpopulation — [(0,1),(1,1)] → []", () => {
12	    expect(nextGeneration([[0, 1], [1, 1]])).toEqual([]);
13	  });
14	  it("a dead cell with exactly 3 live neighbors becomes alive (reproduction) — (1,1) joins output", () => {
15	    const result = nextGeneration([[0, 0], [1, 0], [0, 1]]);
16	    expect(result).toContainEqual([1, 1]);
17	  });
18	  it("a live cell with 2 live neighbors survives (survival)", () => {
19	    const result = nextGeneration([[0, 0], [1, 0], [2, 0]]);
20	    expect(result).toContainEqual([1, 0]);
